:root {
  --bg-dark: #0f1b2d;
  --bg-card: #162236;
  --bg-object: #1e2f45;
  --bg-highlight: #1a3558;
  --accent-primary: #4f9cf9;
  --accent-secondary: #a78bfa;
  --accent-highlight: #fbbf24;
  --text-primary: #e8f0fe;
  --text-secondary: #7ea8d8;
  --text-muted: #4a6a8a;
  --border-color: #243a55;
  --border-highlight: #4f9cf9;
  --badge-bg: #1e2f45;
  --type-planet: #4ade80;
  --type-nebula: #f472b6;
  --type-cluster: #fb923c;
  --type-galaxy: #a78bfa;
  --footer-bg: #0d1824;
}

.planner {
  background-color: var(--bg-dark);
  border: 1px solid var(--border-color);
  border-radius: 16px;
  width: 520px;
  overflow: hidden;
}

.planner-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 18px;
  background-color: var(--bg-card);
  border-bottom: 1px solid var(--border-color);
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.header-label {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.12em;
  color: var(--accent-primary);
  text-transform: uppercase;
}

.header-title {
  font-size: 22px;
  font-weight: 800;
  color: var(--text-primary);
  margin: 0;
  line-height: 1.1;
}

.moon-badge {
  display: flex;
  align-items: center;
  gap: 6px;
  background-color: var(--badge-bg);
  border: 1px solid var(--border-color);
  border-radius: 20px;
  padding: 6px 12px;
}

.moon-icon {
  font-size: 16px;
  line-height: 1;
}

.moon-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-secondary);
}

.planner-body {
  padding: 14px 18px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.conditions-row {
  display: flex;
  gap: 0;
  border: 1px solid var(--border-color);
  border-radius: 10px;
  overflow: hidden;
}

.condition-item {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 10px 8px;
  gap: 3px;
  border-right: 1px solid var(--border-color);
  background-color: var(--bg-card);
}

.condition-item:last-child {
  border-right: none;
}

.condition-value {
  font-size: 16px;
  font-weight: 700;
  color: var(--accent-primary);
  line-height: 1;
}

.condition-label {
  font-size: 10px;
  font-weight: 500;
  color: var(--text-muted);
  text-align: center;
  line-height: 1.2;
}

.objects-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.object-card {
  background-color: var(--bg-object);
  border: 1px solid var(--border-color);
  border-radius: 10px;
  padding: 10px 8px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.object-card.highlight {
  background-color: var(--bg-highlight);
  border-color: var(--border-highlight);
}

.object-type {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.object-card:nth-child(1) .object-type { color: var(--type-planet); }
.object-card:nth-child(2) .object-type { color: var(--type-nebula); }
.object-card:nth-child(3) .object-type { color: var(--type-cluster); }
.object-card:nth-child(4) .object-type { color: var(--type-galaxy); }

.object-name {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.1;
}

.object-time {
  font-size: 11px;
  color: var(--text-secondary);
  font-weight: 500;
}

.object-rating {
  font-size: 10px;
  color: var(--accent-highlight);
  margin-top: 2px;
  letter-spacing: -0.02em;
}

.planner-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 18px;
  background-color: var(--footer-bg);
  border-top: 1px solid var(--border-color);
}

.footer-note {
  font-size: 11px;
  color: var(--text-muted);
  font-weight: 500;
}

.footer-tag {
  font-size: 11px;
  font-weight: 700;
  color: var(--accent-secondary);
  letter-spacing: 0.08em;
}
